#include <pthread.h>
#include <stdlib.h>
#include <stdio.h>

#define NUM_THREADS 4
#define QUEUE_SIZE 100

typedef struct {
    void (*function)(void*);
    void* argument;
} Task;

typedef struct {
    Task queue[QUEUE_SIZE];
    int front, rear, count;
    pthread_mutex_t mutex;
    pthread_cond_t cond;
    int shutdown;
} ThreadPool;

ThreadPool* createPool() {
    ThreadPool* pool = malloc(sizeof(ThreadPool));
    pool->front = pool->rear = pool->count = 0;
    pool->shutdown = 0;
    pthread_mutex_init(&pool->mutex, NULL);
    pthread_cond_init(&pool->cond, NULL);
    return pool;
}

void enqueue(ThreadPool* pool, Task task) {
    pthread_mutex_lock(&pool->mutex);
    if (pool->count < QUEUE_SIZE) {
        pool->queue[pool->rear] = task;
        pool->rear = (pool->rear + 1) % QUEUE_SIZE;
        pool->count++;
    }
    pthread_cond_signal(&pool->cond);
    pthread_mutex_unlock(&pool->mutex);
}

Task dequeue(ThreadPool* pool) {
    pthread_mutex_lock(&pool->mutex);
    while (pool->count == 0 && !pool->shutdown) {
        pthread_cond_wait(&pool->cond, &pool->mutex);
    }
    Task task = {NULL, NULL};
    if (pool->count > 0) {
        task = pool->queue[pool->front];
        pool->front = (pool->front + 1) % QUEUE_SIZE;
        pool->count--;
    }
    pthread_mutex_unlock(&pool->mutex);
    return task;
}

void* worker(void* arg) {
    ThreadPool* pool = (ThreadPool*)arg;
    while (1) {
        Task task = dequeue(pool);
        if (task.function != NULL) {
            task.function(task.argument);
        } else if (pool->shutdown) {
            break;
        }
    }
    return NULL;
}

int main() {
    ThreadPool* pool = createPool();
    pthread_t threads[NUM_THREADS];

    for (int i = 0; i < NUM_THREADS; i++) {
        pthread_create(&threads[i], NULL, worker, pool);
    }

    // Submit tasks
    for (int i = 0; i < 10; i++) {
        Task t = {printTask, (void*)(long)i};
        enqueue(pool, t);
    }

    sleep(1);
    pool->shutdown = 1;
    pthread_cond_broadcast(&pool->cond);

    for (int i = 0; i < NUM_THREADS; i++) {
        pthread_join(threads[i], NULL);
    }

    return 0;
}

// Java uses One-to-One model (each Java thread = native OS thread)

// Method 1: Extending Thread class
class MyThread extends Thread {
    public void run() {
        System.out.println("Thread running: " + getName());
    }
}

// Method 2: Implementing Runnable interface
class MyRunnable implements Runnable {
    public void run() {
        System.out.println("Runnable running in: " + Thread.currentThread().getName());
    }
}

// Method 3: Using Thread Pool (Executor Framework)
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

class Task implements Runnable {
    private int taskId;

    public Task(int id) { this.taskId = id; }

    @Override
    public void run() {
        System.out.println("Task " + taskId + " executing in " + 
            Thread.currentThread().getName());
    }
}

public class ThreadDemo {
    public static void main(String[] args) {
        // One-to-One: Each Java thread maps to native OS thread
        Thread t1 = new MyThread();
        t1.start();

        Thread t2 = new Thread(new MyRunnable());
        t2.start();

        // Thread Pool - reuses threads (Many-to-Many conceptually)
        ExecutorService executor = Executors.newFixedThreadPool(3);

        for (int i = 1; i <= 6; i++) {
            executor.submit(new Task(i));
        }

        executor.shutdown();

        // Demonstrating thread synchronization
        class Counter {
            private int count = 0;
            synchronized void increment() { count++; }
            synchronized int get() { return count; }
        }

        Counter counter = new Counter();

        // Create threads that increment counter
        for (int i = 0; i < 100; i++) {
            new Thread(() -> counter.increment()).start();
        }

        try { Thread.sleep(100); } catch (Exception e) {}
        System.out.println("Final count: " + counter.get());
    }
}
